// PCA Ordination & Licensure Study — per-card MCQ overlay: theology.
// Hand-authored multiple-choice for cards that can't auto-generate one, keyed
// by card id and merged into window.PCA_CARD_QUIZ (consumed by
// js/app/quiz.js cardQuiz()). Kept OUTSIDE the generated subject files so a
// builder re-run never wipes these. Each entry:
//   'card-id': { q?: 'sharper question override', choices: [4], answerIndex }
// Distractors must match the correct answer in length and grammatical shape
// (dev/validate.mjs giveaway check + manual discipline).
(function (global) {
  const Q = {
    // ── A. The Bible ──────────────────────────────────────────────────
    'th-001-define-and-distinguish-general-rev': { q: 'Which best distinguishes general revelation from special revelation?', choices: ['General revelation is God’s self-disclosure to all people through creation and conscience, while special revelation is his particular communication to specific persons through Scripture.', 'General revelation is God’s saving self-disclosure given only through Scripture, while special revelation is his disclosure to all people through creation and conscience.', 'General revelation is the Spirit’s inward witness given to individual believers, while special revelation is the church’s official teaching passed down through tradition.', 'General revelation is the covenant of grace revealed uniquely to national Israel, while special revelation is the light of nature given equally to every nation.'], answerIndex: 0 },
    'th-002-define-and-defend-including-script': { q: 'What best defines the doctrine of “inspiration,” per WCF I.2 and WLC 4?', choices: ['The supernatural illumination given to modern readers, so that any sincere interpretation becomes God’s own word.', 'The supernatural work of the Holy Spirit on the biblical writers, so that what they wrote is accurately God’s own word.', 'The church’s official decision to grant certain writings the same authority as God’s own word.', 'The general religious influence common to great writings, so that readers feel a sense of God’s own word.'], answerIndex: 1 },
    'th-003-define-and-defend-the-necessity-of': { q: 'What does the “necessity” of Scripture mean?', choices: ['Scripture is necessary for knowing that God exists, since nature and conscience reveal nothing of him at all.', 'Scripture is helpful for knowing the gospel but not strictly necessary, since sincere seekers may be saved apart from it.', 'Scripture is necessary for knowing the gospel and God’s will for salvation, though not for knowing that God exists at all.', 'Scripture is necessary only for ordained officers, since ordinary believers may rely on tradition and the Spirit’s leading.'], answerIndex: 2 },
    'th-004-what-is-the-canon-defend-it-script': { q: 'What is the “canon” of Scripture?', choices: ['The list of books the church created by conciliar decree, later invested with the authority of an apostolic origin.', 'The list of every ancient religious writing that mentions Israel’s God, regardless of its theological consistency.', 'The list of books whose authorship remains permanently debated, held provisionally pending further manuscript finds.', 'The list of books recognized by the church as belonging in the Bible, on the basis of apostolic authority, not decree.'], answerIndex: 3 },
    'th-005-define-and-defend-the-authority-of': { q: 'On what does the authority of Scripture rest, per WCF I.4?', choices: ['God himself, its divine author, rather than the testimony of any man or church.', 'The testimony and ratification of church councils that formally approved each book.', 'The personal conviction each reader feels when Scripture resonates with experience.', 'The antiquity and literary excellence of its authors compared to other ancient texts.'], answerIndex: 0 },
    'th-006-define-and-defend-the-sufficiency': { q: 'What does the “sufficiency” of Scripture mean, per WCF I.6?', choices: ['Scripture contains most things necessary for salvation, but the church’s traditions must supply what remains.', 'Scripture contains everything necessary for salvation, faith, and life, so nothing may be added by new revelations.', 'Scripture is sufficient for private devotion, but official doctrine still requires ongoing new revelations.', 'Scripture is sufficient for ethical guidance only, while private gnosis passed among elders reveals salvation itself.'], answerIndex: 1 },
    'th-007-define-and-defend-the-perspicuity': { q: 'What does the “perspicuity” (clarity) of Scripture mean?', choices: ['Every verse of Scripture is equally clear, so no passage ever requires careful study or comparison.', 'Only trained clergy can rightly grasp Scripture’s saving message, since ordinary readers easily misread it.', 'The central saving message of Scripture is clear enough that ordinary people, using ordinary means, can grasp it.', 'Scripture’s meaning shifts with each generation’s culture, so no fixed saving message can be identified.'], answerIndex: 2 },
    'th-008-what-is-distinctive-about-reformed': { q: 'What is distinctive about Reformed interpretation of Scripture, per WLC 156?', choices: ['Only ordained priests may read Scripture at all, since the laity risk grave doctrinal error.', 'Each reader may interpret Scripture freely, with no reference to the church’s historic creeds.', 'The church’s magisterium alone possesses the authority to determine Scripture’s true meaning.', 'Every believer has the right and duty to read and interpret Scripture personally, without a priest’s mediation.'], answerIndex: 3 },
    'th-009-what-principles-should-guide-our-i': { q: 'Which principle should guide interpretation of Scripture, per WCF I.9?', choices: ['Scripture interprets Scripture — unclear passages are searched out and known by other, clearer passages.', 'Church tradition interprets Scripture — unclear passages are settled by councils rather than by other texts.', 'Personal experience interprets Scripture — unclear passages are resolved by each reader’s private feelings.', 'Historical criticism interprets Scripture — unclear passages are resolved by reconstructing the author’s psychology.'], answerIndex: 0 },
    'th-010-define-and-defend-including-script': { q: 'What does the “inerrancy” of Scripture mean?', choices: ['Scripture in its current translations is verbally identical to the original manuscripts in every detail.', 'Scripture in the original manuscripts does not affirm anything that is contrary to fact.', 'Scripture’s central spiritual message is true even though many of its historical claims are legendary.', 'Scripture is inerrant only in matters of faith and morals, and may err in history or science.'], answerIndex: 1 },
    'th-011-what-do-the-scriptures-principally': { q: 'Per WSC 3, what do the Scriptures principally teach?', choices: ['What man is to build concerning society, and what laws the state requires of man.', 'What man is to feel concerning himself, and what practice fulfillment requires of man.', 'What man is to believe concerning God, and what duty God requires of man.', 'What man is to know concerning history, and what customs each culture requires of man.'], answerIndex: 2 },
    // ── B. God & His World ───────────────────────────────────────────
    'th-012-what-is-god': { q: 'Per WSC 4, what is God?', choices: ['A Spirit, finite in power though infinite in his goodness, holiness, justice, and truth.', 'The highest being within the created order, surpassing all creatures in wisdom, power, and holiness.', 'An impersonal force pervading the universe, unchangeable in its power, presence, and justice.', 'A Spirit, infinite, eternal, and unchangeable, in his being, wisdom, power, holiness, justice, goodness, and truth.'], answerIndex: 3 },
    'th-013-briefly-explain-and-defend-includi': { q: 'Which statement best expresses the doctrine of the Trinity?', choices: ['God eternally exists as three persons, Father, Son, and Holy Spirit, and each person is fully God, yet there is one God.', 'God is one person who successively reveals himself in three modes, as Father, then Son, then Holy Spirit.', 'God the Father alone is fully God, while the Son and the Holy Spirit are exalted creatures subordinate to him.', 'Father, Son, and Holy Spirit are three separate gods who cooperate in perfect unity of purpose and will.'], answerIndex: 0 },
    'th-014-what-are-the-attributes-of-god-be': { q: 'How does theology distinguish God’s communicable and incommunicable attributes?', choices: ['Communicable attributes are qualities God once had but has since laid aside, while incommunicable attributes remain his forever.', 'Communicable attributes are qualities God shares with his creatures, such as knowledge and love, while incommunicable attributes, such as eternity and omnipresence, belong to God alone.', 'Communicable attributes describe God’s acts of creation and providence, while incommunicable attributes describe his inner nature apart from any acts.', 'Communicable attributes are revealed only in Scripture, while incommunicable attributes are known only through general revelation.'], answerIndex: 1 },
    'th-015-what-are-the-decrees-of-god': { q: 'Per WSC 7, what are the decrees of God?', choices: ['His ongoing responses to human choices, by which he continually adjusts his plans to fit what creatures freely decide.', 'His general wishes for creation, which he hopes will come to pass but cannot guarantee against human resistance.', 'His eternal purpose, according to the counsel of his will, whereby, for his own glory, he foreordained whatsoever comes to pass.', 'His temporary plans for national Israel, later abandoned once the church replaced Israel as God’s people.'], answerIndex: 2 },
    'th-016-what-is-the-difference-between-inf': { q: 'What is the key difference between supralapsarianism and infralapsarianism?', choices: ['Supralapsarianism denies that God decreed the fall at all, while infralapsarianism affirms he decreed and directly caused it.', 'Supralapsarianism teaches a universal atonement for all, while infralapsarianism restricts the atonement’s intent to the elect.', 'Supralapsarianism holds predestination is conditioned on foreseen faith, while infralapsarianism holds it is wholly unconditional.', 'Supralapsarianism places the decree to elect before the decree to permit the fall, while infralapsarianism places it after.'], answerIndex: 3 },
    'th-017-what-is-an-amyraldian-view-of-god': { q: 'What distinguishes the Amyraldian view of God’s decrees from the Reformed consensus?', choices: ['Christ dies for all conditioned on belief, and the Spirit is then given effectually only to the elect — hypothetical universal predestination.', 'Christ dies only for the elect, and the Spirit is then offered indiscriminately to all who ask for it.', 'All people are predestined to salvation unconditionally, with no place for reprobation of any kind.', 'Election is based on God’s foreknowledge of each person’s inherent goodness and moral effort.'], answerIndex: 0 },
    'th-018-how-does-god-execute-his-decrees': { q: 'Per WSC 8, how does God execute his decrees?', choices: ['In the works of judgment and destruction alone.', 'In the works of creation and providence.', 'In the sacraments and the preaching of the Word alone.', 'In the covenant of works given only to Adam.'], answerIndex: 1 },
    'th-019-what-is-god-s-work-of-creation': { q: 'Per WSC 9, what is the work of creation?', choices: ['God’s making all things out of pre-existing matter, shaped gradually over long ages into their present forms.', 'God’s making the spiritual realm alone, leaving the material world to arise through natural processes.', 'God’s making all things of nothing, by the word of his power, in the space of six days, and all very good.', 'God’s making all things of nothing in a single timeless moment, with no sequence of days at all.'], answerIndex: 2 },
    'th-020-briefly-discuss-the-length-of-the': { q: 'Which pairing of a creation-days theory with its view of “day” is correct?', choices: ['Day-age theory: a sequential, literal reading in which each creation day is a normal 24-hour period.', 'Literary framework theory: a chronological record in which each day marks a distinct geological epoch.', 'Two-phase theory: a single 24-hour day with no possible gap between Genesis 1 and 2.', '24-hour day theory: a sequential, literal reading in which each creation day is a normal 24-hour period.'], answerIndex: 3 },
    'th-021-evaluate-biblically-the-theory-of': { q: 'What is the biblical evaluation of macro-evolutionary theory, per the card?', choices: ['Micro-evolution is a fact, but extrapolating it into full macro-evolution is scientifically suspect and conflicts with Genesis 2-3 and Romans 5 on the origin of death.', 'Both micro- and macro-evolution are fully compatible with Genesis, since death entered creation long before Adam’s sin.', 'Macro-evolution is certain science that Christians must simply reinterpret Genesis 1-3 to accommodate.', 'Neither micro- nor macro-evolution has any observable basis, so all genotypic change in species must be denied.'], answerIndex: 0 },
    'th-022-what-are-god-s-work-s-of-providenc': { q: 'Per WSC 11, what are God’s works of providence?', choices: ['His occasional interventions in a world otherwise left to run by chance and impersonal natural law.', 'His most holy, wise, and powerful preserving and governing of all his creatures and all their actions.', 'His governing of the church alone, leaving the natural world to operate independently of him.', 'His preserving only the elect, while abandoning the reprobate and the created order to themselves.'], answerIndex: 1 },
    'th-023-what-is-a-miracle': { q: 'How does WCF V.3 and Berkhof define a miracle?', choices: ['Any surprising or improbable event in nature, however it may ultimately be explained by ordinary secondary causes.', 'God’s ordinary providence, working exclusively through the normal means he has established in creation.', 'A supernatural work of God, done without recourse to the ordinary means by which he usually governs.', 'A psychological experience of wonder in the believer, regardless of whether anything unusual actually occurred.'], answerIndex: 2 },
    'th-024-do-miracles-occur-today-explain': { q: 'Do miracles occur today, per the card’s answer?', choices: ['No, miracles ceased entirely and permanently once the apostolic age and the canon of Scripture closed.', 'Yes, and miracle-working today should be expected as the ordinary experience of every believer.', 'No, every reported healing today can be fully explained by natural, ordinary secondary causes.', 'Yes, though rarely — God is free to work outside ordinary providence at his pleasure, though not as the apostolic norm.'], answerIndex: 3 },
    'th-025-is-god-responsible-for-sin': { q: 'Is God responsible for sin, per WCF III.1 and V.4?', choices: ['No — God ordains whatsoever comes to pass, yet he is not the author of sin; its sinfulness proceeds only from the creature.', 'Yes — since God ordains whatsoever comes to pass, he must also be the author and approver of sin itself.', 'No — God merely observes sin from a distance and has no decree relating to it whatsoever.', 'Yes — God is equally the author of good and evil, since both proceed from his single, undifferentiated will.'], answerIndex: 0 },
    'th-026-if-god-is-good-and-all-powerful-ex': { q: 'How does the card explain suffering such as AIDS, deformed babies, and natural disasters, given God’s goodness and power?', choices: ['Such suffering proves that God, though good, lacks the power to prevent evil in a fallen world.', 'The world is fallen because of Adam’s sin, so tragedy afflicts even the innocent, and Job teaches us to trust the giver above his gifts.', 'Such suffering falls only on the especially wicked, as direct, individual punishment for particular sins.', 'Such suffering is an illusion, since a good and all-powerful God would never permit any real affliction.'], answerIndex: 1 },
    'th-027-discuss-the-biblical-teaching-rega': { q: 'Per WCF III.3-8, how does the Bible teach predestination, election, and reprobation?', choices: ['God predestines everyone equally to everlasting life, so reprobation is not a genuine biblical category at all.', 'God elects based on foreseeing which individuals would freely choose faith and persevere in it.', 'God has predestinated some to everlasting life in Christ and foreordained others to everlasting death for their sin, to be handled with prudence.', 'God elects entire nations corporately, with no reference to the eternal destiny of individual persons.'], answerIndex: 2 },
    'th-028-distinguish-the-reformed-and-armin': { q: 'How does the card distinguish the Reformed and Arminian views of predestination?', choices: ['Reformed theology holds conditional election based on foreseen faith, while Arminians hold it is wholly unconditional.', 'Reformed theology and Arminian theology agree entirely on predestination, differing only on the nature of the church.', 'Reformed theology denies election altogether, while Arminians affirm unconditional election in eternity past.', 'Reformed theology holds unconditional election in Christ, while Arminians hold conditional predestination based on foreseen faith.'], answerIndex: 3 },
    'th-029-are-these-doctrines-compatible-wit': { q: 'Are God’s sovereign decrees compatible with real human choice and responsibility, per the card?', choices: ['Yes — Scripture is compatibilistic: Genesis 50:20 and Acts 2:23 show God standing sovereignly behind human choices for which people remain genuinely responsible.', 'No — if God ordains all things, human choices must be a complete illusion with no real responsibility attached.', 'Yes, but only because God’s decrees are actually conditioned on and reactive to human choices he foresees.', 'No — Scripture teaches that human responsibility applies only in matters God has not decreed in advance.'], answerIndex: 0 },
    'th-030-what-should-be-some-of-the-practic': { q: 'What practical results does WCF III.8 draw from the doctrine of election?', choices: ['Complacency about evangelism, since the elect will be saved regardless of whether anyone shares the gospel with them.', 'Gratitude for unmerited adoption, assurance that salvation is secure in God, and evangelistic zeal since the Lord has other sheep to gather.', 'Anxious self-examination that never reaches assurance, since no one can know whether they are truly elect.', 'Pride in one’s own spiritual achievement, since being chosen shows one is inherently better than others.'], answerIndex: 1 },
    'th-031-is-there-a-real-personal-devil-exp': { q: 'Is there a real, personal devil, per the card’s answer from Scripture?', choices: ['No — the devil is merely a literary personification of impersonal evil forces within the human heart.', 'Yes, but only as an equal and opposite power locked in eternal struggle with God.', 'Yes — the temptation accounts, such as Matthew 4:1-11, portray the devil as both real and personal.', 'No — Scripture never actually portrays the devil as a distinct personal being at all.'], answerIndex: 2 },
    // ── C. Humankind ─────────────────────────────────────────────────
    'th-032-what-is-the-chief-end-of-man': { q: 'Per WSC 1, what is the chief end of man?', choices: ['To pursue personal happiness, and to enjoy the created world forever.', 'To obey the state, and to serve the common good of society forever.', 'To perfect the self, and to attain enlightenment through inner reflection.', 'To glorify God, and to enjoy him forever, doing all things to his glory.'], answerIndex: 3 },
    'th-033-what-is-the-supreme-activity-of-ma': { q: 'Per WSC 39, what does God require of man?', choices: ['Obedience to his revealed will, as made known to us in his Word.', 'Obedience to the traditions handed down by the church fathers.', 'Obedience to whatever conscience judges best in the moment.', 'Obedience to the civil laws enacted by each person’s nation.'], answerIndex: 0 },
    'th-034-what-does-the-bible-teach-about-th': { q: 'Per WSC 10, how did God create human beings?', choices: ['Male and female, after the image of the angels, in strength and beauty, with dominion over the angels themselves.', 'Male and female, after his own image, in knowledge, righteousness, and holiness, with dominion over the creatures.', 'As a single androgynous being later divided by God into a male half and a female half.', 'Male and female, evolved gradually from earlier animal forms, with no direct act of divine creation.'], answerIndex: 1 },
    'th-035-in-what-way-is-man-created-in-the': { q: 'In what way is man created in the image of God, per the card?', choices: ['Only structurally, through physical endowments like strength and physical beauty, with no functional dimension.', 'Only functionally, through ruling creation, with no structural endowments of rationality or morality involved.', 'Both functionally — ruling creation, loving God and neighbor — and structurally, through rationality, morality, and spirituality.', 'Only mystically, through an unknowable spark of divinity that grants no discernible capacities at all.'], answerIndex: 2 },
    'th-036-are-all-men-in-the-image-of-god-if': { q: 'Are all men in the image of God, and to what extent, per the card?', choices: ['Yes, but only believers retain the image of God, since unbelievers forfeited it entirely at the fall.', 'No, only Adam and Eve bore God’s image; their descendants inherit no trace of it at all.', 'Yes, and the fall left the image of God completely untouched and unaffected in every man.', 'Yes, all are created in God’s image, though the fall has marred its functional exercise while its structural aspect remains.'], answerIndex: 3 },
    'th-037-how-does-the-doctrine-of-the-image': { q: 'How does the doctrine of the image of God inform the debate about gender roles, per the card?', choices: ['Men and women are equal in worth and dignity as image-bearers, yet Adam’s prior creation implies headship authority in the relationship.', 'Men and women are unequal in worth as image-bearers, since only the man fully bears God’s image.', 'Men and women are equal in worth and interchangeable in every role, since headship is nowhere implied by creation order.', 'Men and women are equal in worth, but the woman’s prior creation implies her headship authority in the relationship.'], answerIndex: 0 },
    'th-038-where-did-man-s-soul-come-from-whe': { q: 'Which of these correctly pairs a view of the soul’s origin with its definition?', choices: ['Creationism: the soul is propagated along with the body at generation, transmitted to children by their parents.', 'Traducianism: the soul is propagated along with the body at generation, transmitted to children by their parents.', 'Pre-existence: the soul is an immediate creation of God at a determinate moment after conception.', 'Traducianism: the soul existed in a previous state before being joined to the body at birth.'], answerIndex: 1 },
    'th-039-what-is-sin-see-wsc-14-include-scr': { q: 'Per WSC 14, what is sin?', choices: ['Any feeling of guilt or shame that a person experiences before God or others.', 'Any cultural custom that a particular society happens to regard as taboo.', 'Any want of conformity unto, or transgression of, the law of God.', 'Any failure to achieve one’s full personal potential in life.'], answerIndex: 2 },
    'th-040-discuss-the-guilt-of-sin-and-the-c': { q: 'How does WSC 18 distinguish the guilt and the corruption belonging to fallen man’s estate?', choices: ['Guilt is the corruption of nature inherited from Adam, while corruption is the actual sin each person personally commits.', 'Guilt belongs only to Adam himself, while corruption is inherited by all his descendants without any guilt at all.', 'Guilt and corruption are simply two names for the very same reality, with no distinction between them.', 'Guilt is inherited from Adam’s first sin, while corruption is the resulting want of original righteousness and depravity of nature.'], answerIndex: 3 },
    'th-041-define-and-discuss-original-sin-in': { q: 'Per WSC 16-18, what is original sin?', choices: ['Mankind, descending from Adam by ordinary generation, sinned in him and fell with him, inheriting guilt and corruption from his first transgression.', 'Each person’s own first personal sin, committed independently of any connection to Adam’s transgression.', 'A merely symbolic label for humanity’s collective bad example, with no actual guilt or corruption inherited.', 'A corruption that affects only the body, leaving the soul and will entirely untouched by Adam’s fall.'], answerIndex: 0 },
    'th-042-how-can-original-sin-be-reconciled': { q: 'How can original sin be reconciled with the canons of justice, per the card?', choices: ['It cannot be reconciled; original sin is simply an unjust and arbitrary doctrine with no coherent defense.', 'Total depravity and inability do not relieve man of moral obligation, because his inability is self-imposed, grounded in Adam’s sin.', 'Man’s inability excuses him of all moral obligation, since he cannot be blamed for a nature he never chose.', 'God imposed the inability directly on each person at birth, apart from any connection to Adam’s sin.'], answerIndex: 1 },
    'th-043-is-there-any-good-remaining-in-a-f': { q: 'Is there any good remaining in a fallen, sinful man, per WCF VI.4 and IX.3?', choices: ['Fallen man retains full spiritual ability to please God and prepare himself for salvation by his own strength.', 'Fallen man has no good whatsoever remaining, since the fall entirely erased the image of God from him.', 'Fallen man is utterly indisposed to spiritual good unto salvation, yet because he still bears God’s image, some natural good remains.', 'Fallen man’s corruption affects only his outward actions, leaving his inward will spiritually unaffected.'], answerIndex: 2 },
    'th-044-in-what-ways-does-man-sin': { q: 'In what ways does man sin, per the card’s definition (WSC 14)?', choices: ['Only by actively transgressing God’s law, since falling short of it in mere want of conformity is not truly sin.', 'Only by wanting due conformity to God’s law, since active transgression is a separate category altogether.', 'Only by breaking civil statutes, since the moral law of God no longer defines sin under the new covenant.', 'Both by wanting the due conformity to God’s law that he requires and by actively transgressing that law in thought, word, or deed.'], answerIndex: 3 },
    'th-045-what-are-some-of-the-consequences': { q: 'Per WSC 18-19, what are the consequences of the fall into sin?', choices: ['Loss of communion with God, being under his wrath and curse, and liability to misery in this life, death, and hell forever.', 'A temporary estrangement from God that resolves automatically for everyone once natural life ends.', 'Only physical death, with no liability to divine wrath, misery, or eternal punishment at all.', 'Merely a diminished self-esteem, without any objective change in one’s standing before God.'], answerIndex: 0 },
    'th-046-is-the-will-of-man-free-explain-in': { q: 'How does WCF IX describe the freedom of man’s will across each state?', choices: ['Adam’s will was already enslaved to sin before the fall, just as every sinner’s and believer’s will remains.', 'Adam’s will was free to good or evil before the fall; the sinner’s will is enslaved to sin; the believer’s will is freed by grace, though imperfectly.', 'The sinner’s will retains full ability to turn to God unaided, exactly as Adam’s will did before the fall.', 'The believer’s will becomes perfectly free and sinless the moment of conversion, willing only what is good.'], answerIndex: 1 },
    // ── D. God's Way of Salvation ────────────────────────────────────
    'th-047-what-is-a-covenant': { q: 'What is a covenant, per the card?', choices: ['A unilateral gift given without any conditions, promises, or obligations placed on either party.', 'A private inner feeling of commitment that requires no outward ceremony or stipulated terms.', 'A pact or agreement between two parties, confirmed by a solemn ceremony, binding each to promises on stipulated conditions.', 'A temporary truce between hostile parties that lapses automatically once tensions subside.'], answerIndex: 2 },
    'th-048-what-is-the-covenant-of-works-life': { q: 'Per WCF VII.2, what is the Covenant of Works (Life)?', choices: ['The first covenant made with man, wherein life was promised to Adam upon condition of imperfect, sincere obedience alone.', 'The covenant made with Noah, wherein natural blessings were promised upon condition of ritual sacrifice.', 'The covenant made with Abraham, wherein life was promised to his descendants upon condition of circumcision.', 'The first covenant made with man, wherein life was promised to Adam and his posterity upon condition of perfect obedience.'], answerIndex: 3 },
    'th-049-is-there-a-present-validity-to-the': { q: 'Is there a present validity to the Covenant of Works (Life), per the card?', choices: ['Yes and no — Christ has fulfilled its demands so that believers do not have to, receiving the fruits of his work through grace.', 'No, the Covenant of Works was entirely abrogated at the fall and has had no bearing on redemption ever since.', 'Yes, believers today must still perfectly keep the law themselves to earn eternal life, just as Adam did.', 'Yes and no — Christ merely modeled obedience for believers, who must then independently earn their own righteousness.'], answerIndex: 0 },
    'th-050-what-is-the-covenant-of-redemption': { q: 'What is the Covenant of Redemption, per the card?', choices: ['The eternal agreement between the Father and all humanity, conditioned on each person’s foreseen acceptance of the gospel.', 'The eternal agreement between the Father, giving the Son as Head and Redeemer of the elect, and the Son, voluntarily taking their place.', 'The temporal agreement made at Sinai between God and the nation of Israel through the mediation of Moses.', 'The eternal agreement between the Son and the church, in which believers voluntarily take Christ’s place.'], answerIndex: 1 },
    'th-051-discuss-the-covenant-of-grace': { q: 'What is the Covenant of Grace, per WCF VII.3 and WSC 20?', choices: ['God offers sinners life conditioned on their own unaided obedience, with no promise of the Spirit’s help to believe.', 'God offers two distinct covenants of grace, differing in substance between the Old and New Testaments.', 'God freely offers sinners life and salvation by Christ, requiring faith and promising his Spirit — one covenant, differently administered.', 'God offers salvation universally and unconditionally to every person, with reprobation nowhere in view.'], answerIndex: 2 },
    'th-052a-cog-and-abrahamic-covenant': { q: 'How is the Covenant of Grace related to the Abrahamic Covenant, per the card?', choices: ['The covenant of grace was formally established at Sinai, and the Abrahamic covenant was merely a preliminary promise.', 'The covenant of grace has no relation to Abraham; it was first formally established at Pentecost with the church.', 'The covenant of grace was established with Abraham on the sole condition of his descendants’ ritual purity.', 'The covenant of grace was formally established with Abraham, marking the beginning of an institutional church responding to God’s promise by faith.'], answerIndex: 3 },
    'th-052b-cog-and-mosaic-covenant': { q: 'How is the Covenant of Grace related to the Mosaic Covenant, per the card?', choices: ['Sinai was essentially the same covenant as Abraham’s in national form; the law was made subservient to grace, tutoring Israel unto Christ.', 'Sinai replaced Abraham’s covenant entirely with a new covenant of works based purely on law-keeping.', 'Sinai had no connection to Abraham’s covenant, introducing an unrelated ceremonial system for its own sake.', 'Sinai’s law functioned only as Israel’s civil code, with no purpose of increasing the consciousness of sin.'], answerIndex: 0 },
    'th-052c-cog-and-noahic-covenant': { q: 'How is the Covenant of Grace related to the Noahic Covenant, per the card?', choices: ['The Noahic covenant confers saving spiritual blessings only on the elect, identical in scope to the covenant of grace.', 'The Noahic covenant confers natural blessings universally as common grace, differing from yet resting on the covenant of grace.', 'The Noahic covenant has no relation whatsoever to the covenant of grace, arising from a wholly separate divine purpose.', 'The Noahic covenant confers natural blessings only on believers and their seed, excluding the rest of creation.'], answerIndex: 1 },
    'th-053-discuss-the-relationship-between-t': { q: 'How does the card describe the relationship between the Old and New Covenants?', choices: ['They are two entirely separate covenants of grace, differing in substance as well as in administration.', 'They are identical in every respect, with the New Covenant adding no clarity or blessing beyond the Old.', 'They are distinct in administration, yet one in substance — the same promise, redeeming God’s people in Christ, the New superior in blessing.', 'The Old Covenant remains fully in force today, with the New Covenant serving only Gentile believers.'], answerIndex: 2 },
    'th-054-explain-and-defend-with-scripture': { q: 'Per WCF VIII.2, what is the orthodox doctrine of the person of Christ?', choices: ['The eternal Son took a human nature that gradually absorbed and replaced his divine nature at the incarnation.', 'The eternal Son merely appeared to take a human nature, without truly becoming man in any real sense.', 'The eternal Son and the man Jesus are two separate persons, loosely joined in a moral rather than personal union.', 'The eternal Son, of one substance with the Father, took a true human nature, two distinct natures joined in one person, without confusion.'], answerIndex: 3 },
    'th-055a-was-christ-a-human-person': { q: 'Was Christ a human person, per the card’s answer?', choices: ['Not strictly — he was one divine person with two natures, human and divine, rather than a separate human person.', 'Yes — Christ was simply a human person who was later adopted by God and given divine status.', 'No — Christ had a human body only, with no genuine human nature or soul at all.', 'Yes — Christ was two separate persons, a human person and a divine person, joined together.'], answerIndex: 0 },
    'th-055b-does-christ-have-a-soul': { q: 'Does Christ have a soul, per the card’s answer?', choices: ['No — Christ had only a divine nature and a human body, with no human soul of his own.', 'Yes — Christ himself said, “My soul is overwhelmed with sorrow to the point of death” (Matthew 26:38).', 'No — Christ’s divine nature functioned in the place of a human soul, so a distinct soul was unnecessary.', 'Yes, but only in a merely figurative sense, since “soul” in Matthew 26:38 simply means “life.”'], answerIndex: 1 },
    'th-055c-what-is-kenosis': { q: 'What is kenosis, per WLC 46?', choices: ['“Self-emptying” — the term for how Christ emptied himself of his divine nature entirely at the incarnation.', '“Self-emptying” — the term for how the Father emptied himself of glory in sending the Son to be born.', '“Self-emptying” — the term for how Christ, per WLC 46, emptied himself of his glory in taking the form of a servant.', '“Self-emptying” — the term for how the Spirit emptied himself of power at Pentecost to indwell believers.'], answerIndex: 2 },
    'th-055d-did-christ-lay-aside-any-of-his-di': { q: 'Did Christ lay aside any of his divine attributes at the incarnation, per the card?', choices: ['Yes — Christ fully laid aside all of his divine attributes, becoming entirely and only human at the incarnation.', 'No — Christ’s human nature was itself eternal and uncreated, sharing every divine attribute from birth.', 'Yes — Christ laid aside his moral attributes of holiness and goodness while retaining only his power and knowledge.', 'No — “in Christ all the fullness of the Deity lives in bodily form” (Col 2:9), though his body’s locality raises debate over the communicatio idiomatum.'], answerIndex: 3 },
    'th-055e-explain-and-defend-against-the-ear': { q: 'Which pairing of an early Christological heresy with its error is correct, per the card?', choices: ['Arius taught the Son was a created being, heteroousios with the Father, a view condemned at Nicea in 325.', 'Nestorius taught the Son was a created being, heteroousios with the Father, a view condemned at Nicea in 325.', 'Apollinarius taught that Christ only seemed to become a man, a view answered by John 20:24ff.', 'Eutyches taught that Christ’s two natures remained fully distinct, denying any real union between them.'], answerIndex: 0 },
    'th-055f-are-any-of-the-early-heresies-rega': { q: 'Which group does the card identify as still holding an early Christological heresy today?', choices: ['The Eastern Orthodox church, which holds a monophysite Christology in the tradition of Eutyches.', 'The Coptic church, which holds a monophysite Christology in the tradition of Eutyches.', 'The Roman Catholic church, which holds an Arian Christology denying the Son’s full deity.', 'The Anglican church, which holds a Nestorian Christology dividing Christ into two persons.'], answerIndex: 1 },
    'th-055g-explain-and-defend-the-doctrine-of': { q: 'What is the doctrine of the “communication of properties”?', choices: ['The divine nature is gradually transformed into the human nature, so that Christ’s deity becomes fully human over time.', 'The human nature is absorbed into the divine nature, so that Christ’s humanity ceases to have any real properties of its own.', 'The properties of both natures become the properties of the one person, so he can be called almighty yet also a man of sorrows.', 'The two natures exchange properties freely and completely, so the human nature becomes omniscient and the divine nature becomes mortal.'], answerIndex: 2 },
    'th-055h-what-is-the-extra-calvinisticum': { q: 'What is the “extra Calvinisticum,” per the card?', choices: ['Calvin’s view that the Son’s deity was entirely confined within the incarnate flesh, leaving heaven wholly unruled.', 'Luther’s view that the Son’s human nature became omnipresent, sharing fully in the divine attribute of ubiquity.', 'Calvin’s view that the Son set aside his divine nature at the incarnation and resumed it only after the resurrection.', 'Calvin’s view that the Son’s deity was not confined to the incarnate flesh — he ruled the world even while the God-man walked on earth.'], answerIndex: 3 },
    'th-055i-define-the-names-of-christ-jesus-s': { q: 'Which pairing of a name of Christ with its meaning is correct, per the card?', choices: ['“Son of Man” alludes to Christ’s divinity, drawing on Daniel 7:14 as Jesus’ favorite self-designation.', '“Lamb of God” alludes to Christ’s kingly rule, drawing on Daniel 7:14 as his favorite self-designation.', '“Christ” simply means “Sir,” a polite form of address used by his contemporaries before the resurrection.', '“Jesus” means “the anointed one,” translating the Hebrew term for Israel’s coming king.'], answerIndex: 0 },
    'th-055j-how-was-christ-born': { q: 'Per WSC 22, how was Christ born?', choices: ['By taking to himself a true body only, with a divine mind functioning in place of a human soul.', 'By taking to himself a true body and a reasonable soul, conceived by the Holy Ghost in the virgin Mary’s womb, and born without sin.', 'By taking to himself a human nature inherited through Joseph’s natural line, without any virgin conception.', 'By taking to himself an apparent body only, without truly being conceived or born as other men are.'], answerIndex: 1 },
    'th-055k-explain-and-defend-including-scrip': { q: 'How does the card defend the Virgin Birth from Scripture?', choices: ['Isaiah 7:14 prophesied Christ’s resurrection, which Matthew 1:20-25 records as fulfilled through Joseph’s lineage.', 'Isaiah 7:14 has no connection to Christ’s birth; Matthew cites it only in reference to his crucifixion.', 'Isaiah 7:14 prophesied it, and Matthew 1:20-25 records its fulfillment by the Holy Spirit, without inheriting Adam’s sin nature.', 'Matthew 1:20-25 teaches that Joseph, not the Holy Spirit, was the biological father of Jesus.'], answerIndex: 2 },
    'th-055l-trace-the-revelation-of-the-person': { q: 'Which sequence correctly traces the revelation of Christ from the beginning of the Old Testament, per the card?', choices: ['The tower of Babel (Gen 11), the plagues of Egypt (Exod 7-12), and the golden calf (Exod 32), each foreshadowing Christ’s judgment.', 'The flood (Gen 6-9), the Ten Commandments (Exod 20), and the bronze serpent (Num 21), each foreshadowing Christ’s kingship.', 'Cain and Abel (Gen 4), the Tower of Babel (Gen 11), and the golden calf (Exod 32), each foreshadowing Christ’s priesthood.', 'The seed of the woman (Gen 3:15), Melchizedek’s priesthood (Gen 14), the scepter of Judah (Gen 49:10), and the Suffering Servant (Isa 53).'], answerIndex: 3 },
    'th-055m-what-is-the-humiliation-of-christ': { q: 'Per WSC 27, what is the humiliation of Christ?', choices: ['Being born in a low condition, made under the law, undergoing the miseries of this life and the wrath of God, and the cursed death of the cross.', 'Being born in royal splendor, exempt from the law, and reigning visibly over the nations from birth onward.', 'Being raised bodily, ascending to heaven, and sitting at the Father’s right hand in glory and power.', 'Being sanctified and anointed above measure, ruling and defending his church, and interceding for his people.'], answerIndex: 0 },
    'th-055n-define-and-distinguish-the-active': { q: 'How does the card distinguish the active and passive obedience of Christ?', choices: ['Active obedience is Christ’s suffering and death paying the penalty for sin, while passive obedience is his life of perfect obedience.', 'Active obedience is Christ’s life of perfect obedience earning righteousness for us, while passive obedience is his suffering and death paying sin’s penalty.', 'Active obedience refers only to miracles Christ performed, while passive obedience refers only to his teaching ministry.', 'Active and passive obedience both refer to the very same event, Christ’s death, viewed from two different angles.'], answerIndex: 1 },
    'th-055o-what-happened-in-the-resurrection': { q: 'What happened in the resurrection of Christ, per the card?', choices: ['A mere resuscitation identical to Lazarus’s, with no change to the nature or condition of Christ’s body.', 'A purely spiritual event with no bodily component, since Christ’s physical body remained in the tomb.', 'Not mere revival, but human nature restored and raised to a higher level as “the firstfruits of them that slept,” declaring the penalty paid.', 'A symbolic event in the disciples’ memory, without any actual bodily event having taken place at all.'], answerIndex: 2 },
    'th-055p-what-are-the-offices-of-christ-and': { q: 'Per WSC 23-26, what are the offices of Christ, and how does he execute them?', choices: ['Prophet, in ruling the nations; Priest, in revealing God’s will; and King, in interceding for his people before the Father.', 'Priest only, since the offices of prophet and king belonged exclusively to the old covenant and ceased with Christ.', 'Prophet, in offering sacrifice; Priest, in ruling and defending; and King, in revealing God’s will for salvation.', 'Prophet, in revealing God’s will for our salvation; Priest, in offering himself and interceding for us; and King, in ruling and defending us.'], answerIndex: 3 },
    'th-055q-who-is-the-only-redeemer-of-god-s': { q: 'Per WSC 21, who is the only Redeemer of God’s elect?', choices: ['The Lord Jesus Christ, the eternal Son of God, who became man and continues to be God and man in two natures and one person forever.', 'The church collectively, acting as a corporate mediator between God and each individual believer.', 'Every believer individually, who redeems himself through faith and good works over a lifetime.', 'The angels, who mediate between God and the elect until the final day of judgment.'], answerIndex: 0 },
    'th-055r-what-is-a-redeemer': { q: 'What is a redeemer, per the card?', choices: ['One who merely advises someone else on how to escape captivity by their own effort.', 'One who delivers someone else from captivity, securing their release at a cost to himself.', 'One who shares captivity alongside someone else without ever securing their release.', 'One who postpones someone else’s captivity without ever actually ending it.'], answerIndex: 1 },
    'th-055s-what-is-the-atonement': { q: 'What is the atonement, per the card?', choices: ['The work Christ did only in his death, since his life of obedience contributes nothing to our salvation.', 'The work each believer does in his own life to earn favor with God after conversion.', 'The work Christ did in his life and death to earn our salvation, including the benefits flowing from his life, not only his death.', 'The work the church does in administering the sacraments to apply Christ’s life to believers.'], answerIndex: 2 },
    'th-055t-was-the-atonement-necessary-explai': { q: 'Was the atonement necessary, per the card’s answer?', choices: ['It was absolutely necessary in every sense, since God had no freedom whatsoever in deciding whether to save anyone.', 'It was entirely unnecessary, since God could have simply overlooked sin without requiring any atonement at all.', 'It was necessary only for Gentile believers, while Jewish believers were saved through the law without atonement.', 'It was not absolutely necessary for God to save anyone, but once he chose to, there was no other way than through his Son’s death.'], answerIndex: 3 },
    'th-055u-why-isn-t-a-good-life-enough-to-ga': { q: 'Why isn’t a good life enough to gain salvation, per the card?', choices: ['Because all have sinned and fall short of the glory of God, and are by nature objects of wrath.', 'Because God simply prefers faith to good works as a matter of arbitrary personal taste.', 'Because good works are impossible for anyone to perform at all, whether believer or unbeliever.', 'Because a good life would save a person, except that no one has ever managed to live one.'], answerIndex: 0 },
    'th-055v-define-expiation-propitiation-reco': { q: 'How does the card distinguish “expiation” from “propitiation”?', choices: ['Expiation denotes the pacifying of God’s wrath, while propitiation denotes only the restoring of a broken relationship.', 'Expiation denotes the covering or putting away of sin itself, while propitiation includes that and also the pacifying of God’s wrath.', 'Expiation and propitiation are simply two unrelated words for the payment of a ransom price to captors.', 'Expiation denotes imputing Adam’s sin to us, while propitiation denotes imputing Christ’s righteousness to us.'], answerIndex: 1 },
    'th-055w-what-is-the-nature-of-the-atonemen': { q: 'What is the nature of the atonement, and what is “penal substitutionary atonement,” per the card?', choices: ['The atonement is merely subjective, intended only to influence the sinner toward repentance rather than to satisfy God.', 'The atonement is collective only, applying automatically to all humanity with no place for personal substitution.', 'The atonement is objective and vicarious, including Christ’s active and passive obedience — penal substitution unites sacrifice, propitiation, and reconciliation.', 'The atonement is exemplary only, showing us how to live rather than actually satisfying divine justice.'], answerIndex: 2 },
    'th-055x-what-of-christ-s-work-remains-to-b': { q: 'What of Christ’s work remains to be done, per the card?', choices: ['To be born, live a sinless life, and die on the cross, all of which still remain to be accomplished.', 'To ascend to heaven and be seated at the Father’s right hand, an event still awaited by the church.', 'To institute the sacraments of baptism and the Lord’s Supper, which Christ has not yet established.', 'To come again in great power and glory, destroy all dominion and power, defeat death, and judge the world in righteousness.'], answerIndex: 3 },
    'th-055y-were-old-testament-believers-saved': { q: 'Were Old Testament believers saved by Christ, per WCF VIII.6?', choices: ['Yes — the virtue, efficacy, and benefits of redemption were communicated to the elect in all ages through the promises and types in which Christ was revealed.', 'No — Old Testament believers were saved by their own careful obedience to the law rather than by Christ.', 'Yes, but only after Christ’s actual incarnation, so no one prior to Bethlehem could truly be saved.', 'No — salvation by faith in a coming Redeemer is strictly a New Testament category unknown before Christ.'], answerIndex: 0 },
    'th-055z-will-any-for-whom-christ-died-be-l': { q: 'Will any for whom Christ died be lost, per WCF VIII.8?', choices: ['Yes — Christ’s redemption merely makes salvation possible, leaving the final outcome entirely uncertain.', 'No — to all for whom Christ purchased redemption, he certainly and effectually applies it, so none of his sheep can ever be snatched away.', 'Yes — some for whom Christ died will ultimately be lost through no fault or choice of their own.', 'No, but only because believers themselves keep hold of Christ through their own unaided perseverance.'], answerIndex: 1 },
    // ── E. Salvation Accomplished ────────────────────────────────────
    'th-056-what-is-the-ordo-salutis-support-y': { q: 'What is the correct order in the ordo salutis, per the card?', choices: ['Glorification, justification, regeneration, election, effectual calling, adoption, sanctification, faith, repentance, and perseverance.', 'Sanctification, election, glorification, regeneration, justification, adoption, effectual calling, faith, repentance, and perseverance.', 'Election, gospel call, effectual calling, regeneration, repentance and faith, justification, adoption, sanctification, and glorification.', 'Regeneration, election, adoption, justification, glorification, effectual calling, sanctification, faith, repentance, and perseverance.'], answerIndex: 2 },
    'th-057-how-would-you-explain-the-plan-of': { q: 'Which sequence correctly summarizes the simple plan of salvation, per the card?', choices: ['God is holy, all have sinned, but sincere effort at good works alone is sufficient to earn eternal life.', 'God is distant and uninvolved, humanity is basically good, and salvation comes through self-improvement alone.', 'God is holy, only some have sinned, and Christ died only for those who first proved themselves worthy.', 'God is holy, all have sinned, sin earns death but God gives life, Christ died for sinners, received by grace through faith, not works.'], answerIndex: 3 },
    'th-058-define-and-defend-include-scriptur': { q: 'Per WSC 31, what is “effectual calling”?', choices: ['The work of God’s Spirit, convincing us of our sin, enlightening our minds in Christ, and renewing our wills to embrace him.', 'The work of the sinner’s own will, convincing himself of his sin and choosing to embrace Christ unaided.', 'The general invitation of the gospel preached to all, without any inward work of the Spirit accompanying it.', 'The work of the church’s sacraments alone, apart from any inward work of conviction or renewal by the Spirit.'], answerIndex: 0 },
    'th-059-on-what-is-god-s-decision-to-call': { q: 'On what is God’s decision to call a certain person based, per WCF X.2?', choices: ['God’s foreseeing which persons would freely choose to respond, conditioning his call on their anticipated faith.', 'God’s free and special grace alone, not from anything foreseen in man, who is passive until quickened by the Spirit.', 'The sinner’s own inherent goodness, which God recognizes and rewards with his effectual call.', 'The church’s formal decision to extend an outward call to those it judges most likely to respond.'], answerIndex: 1 },
    'th-060-how-can-infants-be-called': { q: 'How can infants be “called,” per WCF X.3?', choices: ['No infant can be saved, since the outward preaching of the Word is strictly necessary for the Spirit to work at all.', 'All infants without exception are automatically saved, since infancy itself removes any need for the Spirit’s work.', 'Elect infants dying in infancy are regenerated and saved by Christ through the Spirit, who works when and how he pleases.', 'Only infants baptized in infancy can be saved, since baptism itself effects their regeneration.'], answerIndex: 2 },
    'th-061-can-anyone-not-called-by-the-spiri': { q: 'Can anyone not called by the Spirit be saved, per WCF X.1 and X.4?', choices: ['Yes — anyone diligently following the light of nature and the laws of their own religion may also be saved.', 'Yes — common operations of the Spirit alone are sufficient to save those never effectually called.', 'No, but this is merely a matter of church discipline rather than an actual condition for salvation itself.', 'No — God predestinated only those he effectually calls, and it is pernicious to assert others can be saved by nature’s light.'], answerIndex: 3 },
    'th-062-is-jesus-really-the-only-way-of-sa': { q: 'Is Jesus really the only way of salvation, per the card?', choices: ['Yes — “no one comes to the Father except through me” (John 14:6), and salvation is found in no one else, however sincere another’s religion.', 'No — sincere adherents of any religion who diligently follow its laws will also ultimately be saved.', 'Yes, but only for those born into a Christian culture; others are judged by a wholly separate standard.', 'No — general revelation alone is sufficient for salvation, apart from any explicit faith in Christ.'], answerIndex: 0 },
    'th-063-define-and-defend-include-scriptur': { q: 'Per WSC 33, what is “justification”?', choices: ['A process of gradual moral improvement by which God slowly infuses righteousness into the believer over a lifetime.', 'An act of God’s free grace wherein he pardons all our sins and accepts us as righteous, only for Christ’s righteousness imputed and received by faith.', 'An act of the sinner’s own will, whereby he declares himself righteous before God on the basis of his best efforts.', 'An act of the church, whereby the sacraments themselves impart the righteousness necessary for acceptance with God.'], answerIndex: 1 },
    'th-064-what-is-the-basis-of-justification': { q: 'What is the basis of justification, per WCF XI.1?', choices: ['The believer’s own infused righteousness, gradually accomplished by the Spirit’s work within the heart.', 'The believer’s sincere effort at obedience, which God graciously accepts as sufficient for acceptance with him.', 'God’s free grace, on the basis of Christ’s imputed obedience alone — not infused righteousness, not anything wrought in us.', 'The church’s sacramental system, through which grace is dispensed to those who faithfully participate.'], answerIndex: 2 },
    'th-065-explain-this-statement-faith-alone': { q: 'What does “faith alone saves, but saving faith is never alone” mean, per WCF XI.2?', choices: ['Faith and works together are the joint instruments of justification, each contributing equally to our acceptance with God.', 'Works alone justify, since James 2 teaches that faith without deeds accomplishes nothing before God.', 'Faith is one of several equally valid instruments of justification, alongside works, sacraments, and church membership.', 'Faith alone is the sole instrument of justification, yet true saving faith is never alone but works by love.'], answerIndex: 3 },
    'th-066-when-is-a-christian-justified': { q: 'When is a Christian justified, per the card?', choices: ['At the moment of belief — God decreed to justify the elect from eternity, but applies it through the Spirit in due time.', 'At the moment of physical birth, since justification is granted automatically to every person born into the world.', 'At the final judgment alone, so that no believer can have any assurance of justification in this present life.', 'At water baptism alone, since the sacrament itself is what actually accomplishes a person’s justification.'], answerIndex: 0 },
    'th-067-what-happens-when-a-christian-sins': { q: 'What happens when a Christian sins after being justified, per WCF XI.5?', choices: ['They immediately fall out of a state of justification and must be justified all over again by renewed faith.', 'Nothing changes their justified standing, since it rests on Christ’s righteousness, though sin may bring God’s fatherly displeasure.', 'Their justification is only partially affected, requiring a fresh act of imputed righteousness for each sin.', 'Their justification was never genuine in the first place, since a truly justified person could not sin again.'], answerIndex: 1 },
    'th-068-how-were-believers-justified-under': { q: 'How were believers justified under the old covenant, per WCF XI.6?', choices: ['By a different and lesser justification than New Testament believers, since Christ had not yet actually died for their sins.', 'By strict obedience to the ceremonial law, apart from any exercise of faith on their part.', 'The very same way as New Testament believers — one and the same justification, with Abraham as the paradigm of faith.', 'They were not justified at all under the old covenant, only forgiven temporarily until Christ’s death.'], answerIndex: 2 },
    'th-069-define-and-defend-include-scriptur': { q: 'Per WSC 35, what is “sanctification”?', choices: ['The work of the believer’s own unaided willpower, whereby he gradually improves his moral character over time.', 'A single instantaneous event completed entirely at conversion, requiring no further growth afterward.', 'The work of the church’s sacraments alone, which mechanically produce holiness apart from the Spirit’s renewing work.', 'The work of God’s free grace whereby we are renewed after the image of God, dying more and more to sin and living unto righteousness.'], answerIndex: 3 },
    'th-070-can-anyone-become-perfect-complete': { q: 'Can anyone become perfect (completely sanctified) in this life, per WCF XIII.2 and WSC 82?', choices: ['No — sanctification is imperfect in this life, with remnants of corruption remaining, so no mere man can perfectly keep God’s commandments.', 'Yes — mature believers can and often do reach entire, sinless perfection well before physical death.', 'Yes — sanctification is instantly completed at conversion, leaving no remaining corruption whatsoever.', 'No, but only because God has chosen arbitrarily to withhold perfection from believers who could otherwise attain it.'], answerIndex: 0 },
    // ── F. Salvation Applied ─────────────────────────────────────────
    'th-071-what-is-saving-faith-defend-your-a': { q: 'Per WSC 86, what is saving faith?', choices: ['A saving grace whereby we receive and rest upon Christ alone for salvation, as he is offered to us in the gospel.', 'A general moral conviction that a supreme being exists and rewards good conduct in this life.', 'A meritorious human work that God accepts as partial payment toward the debt of sin.', 'An emotional feeling of peace that arises spontaneously apart from any object believed in.'], answerIndex: 0 },
    'th-072-where-does-saving-faith-come-from': { q: 'Where does saving faith come from, per WCF XIV.1?', choices: ['From the sinner’s own unaided decision, made independently before the Spirit does any inward work.', 'From the work of the Spirit of Christ in the heart, ordinarily wrought through the Word, sacraments, and prayer.', 'From inherited family tradition alone, passed down without any working of the Spirit at all.', 'From the church’s formal decree admitting a person to membership in good standing.'], answerIndex: 1 },
    'th-073-what-does-saving-faith-believe-def': { q: 'What are the principal acts of saving faith, per WCF XIV.2?', choices: ['Debating, doubting, and withholding assent until every promise of Scripture is independently verified.', 'Admiring, imitating, and outwardly conforming to Christ’s moral example without any inward trust in him.', 'Accepting, receiving, and resting upon Christ alone for justification, sanctification, and eternal life.', 'Merely assenting intellectually that Christ existed, without any personal reliance on him for salvation.'], answerIndex: 2 },
    'th-074-is-all-faith-alike-defend-your-ans': { q: 'Is all faith alike, per WCF XIV.3?', choices: ['Yes — every believer’s faith is identical in strength and never varies in degree from conversion onward.', 'No — faith differs in degrees, weak or strong, often assailed and weakened, yet growing toward full assurance through Christ.', 'No — some believers possess saving faith while others possess a wholly different, non-saving kind of true faith.', 'Yes — faith’s strength depends entirely on a believer’s inherited temperament rather than on Christ’s work in them.'], answerIndex: 1 },
    'th-075-define-repentance-defend-your-answ': { q: 'Per WSC 87, what is repentance unto life?', choices: ['A saving grace whereby a sinner, sensing his sin and God’s mercy, turns from it to God with grief and hatred of sin, purposing new obedience.', 'A one-time emotional outburst of remorse that need not issue in any lasting change of life or conduct.', 'A merely legal requirement imposed by the church, unrelated to any inward sense of sin or mercy.', 'A human achievement that, once performed, itself earns the pardon of sin apart from Christ’s merit.'], answerIndex: 0 },
    'th-076-in-what-sense-is-repentance-necess': { q: 'In what sense is repentance “necessary,” per WCF XV.3?', choices: ['It is itself the meritorious cause and satisfaction for sin, apart from which pardon could never be granted.', 'It is not rested in as any satisfaction for sin, yet is of such necessity that none may expect pardon without it.', 'It is an optional devotional practice that some mature believers may choose to omit without consequence.', 'It is necessary only for especially grievous sins, while lesser sins require no repentance at all.'], answerIndex: 1 },
    'th-077-how-ought-we-to-confess-our-sins-d': { q: 'How ought believers confess their sins, per WCF XV.5-6?', choices: ['By a general repentance alone, since it is unnecessary to endeavor to repent of particular sins particularly.', 'Only through a priest’s absolution, since private confession directly to God accomplishes nothing.', 'By enduring a fixed period of penance before any assurance of pardon may rightly be received.', 'Every man ought to endeavor to repent of his particular sins particularly, and one who scandalizes another should also confess to them.'], answerIndex: 3 },
    'th-078-what-are-good-works-defend-your-an': { q: 'Per WCF XVI.1, what are good works?', choices: ['Only such as God has commanded in his Word, not works devised by men out of blind zeal or good intention.', 'Any sincerely intended act, whether or not it is commanded anywhere in God’s Word.', 'Whatever a person’s own conscience judges praiseworthy, regardless of Scripture’s commands.', 'Acts of religious devotion invented by church tradition to supplement Scripture’s commands.'], answerIndex: 0 },
    'th-079-what-is-the-relation-of-good-works': { q: 'What is the relation of good works to faith, per WCF XVI.2?', choices: ['Good works are the meritorious ground on which faith itself is granted to the believer.', 'Good works are unrelated to faith, since one may possess either without any bearing on the other.', 'Good works replace faith as the believer matures, becoming the primary ground of acceptance with God.', 'Good works are the fruits and evidences of a true and lively faith, by which believers manifest thankfulness and glorify God.'], answerIndex: 3 },
    'th-080-are-good-works-necessary-for-salva': { q: 'Per WCF XVI.3, from where does believers’ ability to do good works come?', choices: ['Not at all of themselves, but wholly from the Spirit of Christ, requiring his actual influence to will and to do.', 'Entirely from their own natural moral strength, unaided by any working of the Spirit.', 'From the church’s sacraments alone, which mechanically produce the ability apart from the Spirit.', 'From a righteousness infused gradually at baptism that operates independently of ongoing grace.'], answerIndex: 0 },
    'th-081-can-our-good-works-save-us-defend': { q: 'Can believers’ good works merit pardon of sin or eternal life, per WCF XVI.5?', choices: ['Yes, provided the works are performed with sincere and wholehearted effort throughout a lifetime.', 'No — by reason of the disproportion between our works and the glory to come, we cannot merit pardon, having only done our duty.', 'Yes, but only for especially heroic acts of self-sacrifice beyond the ordinary call of duty.', 'No, because God has decreed that good works play no role whatsoever in the Christian life.'], answerIndex: 1 },
    'th-082-can-unbelievers-do-good-works-defe': { q: 'Can unbelievers do good works, per WCF XVI.7?', choices: ['Yes, fully — works done by the unregenerate please God just as much as those done by believers.', 'No, in every sense — unbelievers are incapable of doing anything of good use to themselves or others.', 'In the matter of them, yes, and of good use; but properly no, since they proceed from no heart purified by faith and cannot please God.', 'Yes, and their neglect of such works is therefore no more displeasing to God than their performance of them.'], answerIndex: 2 },
    'th-083-define-and-defend-include-scriptur': { q: 'What is the doctrine of perseverance of the saints?', choices: ['The continuous operation of the Spirit in the believer, by which the work of grace begun in the heart is continued and brought to completion.', 'The believer’s own unaided determination to keep persisting in faith despite the Spirit’s absence from the process.', 'The church’s ongoing discipline, which alone secures a member’s continuance in the faith.', 'A merely hoped-for outcome with no ground in God’s election, Christ’s intercession, or the Spirit’s work.'], answerIndex: 0 },
    'th-084-can-a-saved-person-later-be-eterna': { q: 'Can a saved person later be eternally lost, per WCF XVII.1?', choices: ['Yes — even the truly regenerate may totally and finally fall away from grace and be lost forever.', 'No — those effectually called and sanctified by the Spirit can neither totally nor finally fall away, but shall certainly persevere and be saved.', 'Yes, but only if they commit a single unusually severe sin after their conversion.', 'No, but only because the church’s discipline prevents any believer from ever falling into serious sin.'], answerIndex: 1 },
    'th-085-on-what-does-a-believer-s-persever': { q: 'On what does a believer’s perseverance depend, per WCF XVII.2?', choices: ['Chiefly on the believer’s own free will and continued effort to hold on to Christ unaided.', 'On the immutability of the decree of election, the efficacy of Christ’s merit and intercession, and the abiding Spirit — not on the believer’s free will.', 'On the church’s sacraments alone, apart from any decree of election or work of the Spirit.', 'On God’s foreseeing which believers would freely choose to keep persevering to the end.'], answerIndex: 1 },
    'th-086-can-a-person-be-sure-he-is-saved-d': { q: 'Can a person be sure he is saved, per WCF XVIII.1?', choices: ['No — assurance of salvation in this life is impossible for anyone, however sincerely they believe.', 'Yes, but only hypocrites claim it, since true believers rightly remain permanently uncertain.', 'Yes — those who truly believe in the Lord Jesus and love him in sincerity may in this life be certainly assured they are in a state of grace.', 'Yes, but such assurance is granted only after death, never during earthly life.'], answerIndex: 2 },
    'th-087-should-a-person-be-sure-he-is-save': { q: 'Per WCF XVIII.3, is it a believer’s duty to seek assurance of salvation?', choices: ['No — seeking assurance is a form of spiritual pride better avoided altogether.', 'Yes — it is the duty of every one to give diligence to make his calling and election sure, that his heart may be enlarged in peace and joy.', 'No — assurance belongs to the essence of faith, so every true believer already possesses it without effort.', 'Yes, but only ordained officers are called to this duty, not ordinary believers.'], answerIndex: 1 },
    'th-088-how-could-a-person-know-he-is-save': { q: 'On what is the believer’s infallible assurance founded, per WCF XVIII.2?', choices: ['A bare conjectural and probable persuasion grounded upon a fallible hope, subject to revision.', 'The divine truth of the promises, the inward evidence of the graces to which they are made, and the Spirit’s testimony with our spirits.', 'Extraordinary new revelations given privately to especially mature believers.', 'The outward approval and formal certification of the visible church alone.'], answerIndex: 1 },
    'th-089-what-should-a-person-do-who-lacks': { q: 'What should a person who lacks assurance of salvation do, per WCF XVIII.3?', choices: ['Conclude that he is certainly not among the elect and abandon the pursuit of holiness.', 'Wait passively, since diligence in the means of grace can neither hasten nor help assurance.', 'Give all diligence to make his calling and election sure, using the ordinary means the Spirit has appointed.', 'Seek an extraordinary revelation from God, since ordinary means cannot produce assurance.'], answerIndex: 2 },
  };
  global.PCA_CARD_QUIZ = Object.assign(global.PCA_CARD_QUIZ || {}, Q);
})(typeof window !== 'undefined' ? window : globalThis);
